/**
 * @summary List assets in workspace
 */
export const getListAssetsUrl = (
  workspaceId: string,
  params?: ListAssetsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/workspaces/${workspaceId}/assets?${stringifiedParams}`
    : `/api/workspaces/${workspaceId}/assets`;
};

export const listAssets = async (
  workspaceId: string,
  params?: ListAssetsParams,
  options?: RequestInit,
): Promise<Asset[]> => {
  return customFetch<Asset[]>(getListAssetsUrl(workspaceId, params), {
    ...options,
    method: "GET",
  });
};

